def tug_of_war(arr):
    n = len(arr)
    total_sum = sum(arr)

    if total_sum % 2 != 0:
        return None  # Eşit toplamlı iki alt kümeye bölmek mümkün değilse

    target_sum = total_sum // 2

    dp = [[False for _ in range(target_sum + 1)] for _ in range(n + 1)]

    for i in range(n + 1):
        dp[i][0] = True

    for i in range(1, n + 1):
        for j in range(1, target_sum + 1):
            if arr[i-1] <= j:
                dp[i][j] = dp[i-1][j] or dp[i-1][j - arr[i-1]]
            else:
                dp[i][j] = dp[i-1][j]

    if not dp[n][target_sum]:
        return None #eşit ikiye bölmek mümkün değil

    subset1 = []
    subset2 = []

    i = n
    j = target_sum

    while i > 0 and j >= 0:
        if dp[i-1][j]:
            subset2.append(arr[i-1])
            i -= 1
        else:
            subset1.append(arr[i-1])
            j -= arr[i-1]
            i -= 1

    while i > 0:
        subset2.append(arr[i-1])
        i -= 1

    return subset1, subset2

if __name__ == '__main__':
    arr = [3, 1, 4, 2, 2, 1]
    result = tug_of_war(arr)

    if result:
        subset1, subset2 = result
        print("Alt küme 1:", subset1)
        print("Alt küme 2:", subset2)
        print("Alt küme 1 toplamı:", sum(subset1))
        print("Alt küme 2 toplamı:", sum(subset2))
    else:
        print("Bu dizi eşit toplamlı iki alt kümeye bölünemez.")
